Here is the equivalent code in Swift:

```swift
import Spark

// Create a spark session
let spark = SparkSession.builder()
    .appName("Swift Spark SQL basic example")
    .config("spark.some.config.option", "some-value")
    .getOrCreate()

// Load data from a CSV file into a DataFrame
let df = spark.read.format("com.databricks.spark.csv")
    .options(header: "true", inferschema: "true")
    .load("path/to/your/csv")

// Show the data
df.show()

// Let's say we have a second DataFrame and we want to join them on some column
let df2 = spark.read.format("com.databricks.spark.csv")
    .options(header: "true", inferschema: "true")
    .load("path/to/your/second/csv")

let joined_df = df.join(df2, df["join_column"] == df2["join_column"])

// Now, let's write the DataFrame back to a CSV file
joined_df.write.format("com.databricks.spark.csv").save("path/to/save/csv")

// Stop the spark session
spark.stop()
```

