#include <mutex>
#include <iostream>

class ComplexClass {
private:
    int data;
    std::mutex mtx;

public:
    ComplexClass(int data) : data(data) {}
    ~ComplexClass() {}

    int getData() {
        std::lock_guard<std::mutex> lock(mtx);
        return data;
    }

    void setData(int data) {
        std::lock_guard<std::mutex> lock(mtx);
        this->data = data;
    }

    void incrementData() {
        std::lock_guard<std::mutex> lock(mtx);
        ++data;
    }

    void decrementData() {
        std::lock_guard<std::mutex> lock(mtx);
        --data;
    }

    ComplexClass(const ComplexClass& other) : data(other.data) {}
};
