def correctBracketing(s):
    stack = []
    for char in s:
        if char in ["[", "(", "{"]:
            stack.append(char)
        elif char in ["]", ")", "}"]:
            if not stack:
                return False
            else:
                if char == ")" and stack[-1] != "(":
                    return False
                elif char == "]" and stack[-1] != "[":
                    return False
                elif char == "}" and stack[-1] != "{":
                    return False
                else:
                    stack.pop()
    return not stack
```
