use strict;
use warnings;

sub how_many_times {
    my ($string, $substring) = @_;
    my $count = 0;
    for my $i (0 .. length($string) - length($substring)) {
        if (substr($string, $i, length($substring)) eq $substring) {
            $count++;
        }
    }
    return $count;
}

sub count_subsequences {
    my ($string, $substring) = @_;
    my $m = length($substring);
    my $n = length($string);
    my @dp = (0) x ($m + 1);
    for my $i (0 .. $n) {
        $dp[0] = 1;
    }
    for my $i (1 .. $m) {
        for my $j (1 .. $n) {
            if (substr($substring, $i - 1, 1) eq substr($string, $j - 1, 1)) {
                $dp[$i][$j] = $dp[$i - 1][$j - 1] + $dp[$i][$j - 1];
            } else {
                $dp[$i][$j] = $dp[$i][$j - 1];
            }
        }
    }
    return $dp[$m][$n];
}

sub find_substrings_with_k_distinct_chars {
    my ($string, $k) = @_;
    my @result;
    for my $i (0 .. length($string)) {
        my %distinct_chars;
        my $substring = '';
        for my $j ($i .. length($string)) {
            $substring .= substr($string, $j, 1);
            $distinct_chars{substr($string, $j, 1)} = 1;
            if (keys %distinct_chars == $k) {
                push @result, $substring;
            } elsif (keys %distinct_chars > $k) {
                last;
            }
        }
    }
    return @result;
}
